from flask import Flask, request
import pickle  # Import the library
app = Flask(__name__)


# POST requests to "/upload" will get a model file uploaded and return the deserialized model to the frontend client.
@app.route('/upload', methods=['POST'])
def upload():
    model = pickle.load(request.files['model_file'].stream)  # Get the uploaded file stream, then load it into memory as a serialized model using pickel's built in "load" method.
    return model


if __name__ == "__main__":
   app.run()